INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('public-health-specialist-moex-00427', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '有關壓力、因應與調適中，對於復原力（resilience）之敘述，下列何者錯誤？', '["復原力（resilience）一詞源自拉丁字「resilire」，泛指人或物體具有彈性、韌性或抗壓性， 即使受外力擠壓仍能迅速恢復的一種力量或特質", "依相關理論而言，復原力係指個體面對風險時，能「積極恢復」至正向情緒之因應策略， 無法透過認知教育訓練或環境改變來加以強化", "個人在壓力情境下情緒與認知的平衡，透過自我對話，察覺與轉化情緒，尋找釋放出口， 也是復原力的一部分", "Werner（1995）認為建構復原力涉及三個關鍵環節，分別為風險因子、保護因子和脆弱因子"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00428', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '有關情緒與健康之敘述，下列何者錯誤？', '["透過社會關係與人際互動，適度提供同理心表達、愛、信任與關心，對當事人而言，有助 於其面對壓力源或負面事件", "學者Cassel提出，社會支持是重要的健康社會決定因素，能夠有效降低心理壓力與情緒對 健康危害的影響", "當人們經歷人生重大轉變，例如畢業或結婚，可能為壓力源，亦可能引發疾病發生或影響 健康行為頻率", "對當事人提供自我評價有效的資訊，如有用的回饋與肯定，乃是社會支持類型（House,1981） 分類之「資訊性支持」類型"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00429', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '工作壓力對於個體的身心健康有很大的影響，請問根據工作需求控制模式（Jobdemandcontrol model,Karasek,1979），下列那種工作狀況會產生最大的壓力？', '["高控制、高需求", "低控制、低需求", "低控制、高需求", "高控制、低需求"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00430', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '自殺是一項全球性公共衛生問題，有關自殺防治之敘述，下列何者錯誤？', '["人際關係與社會支持系統能提供支持力量以扮演自殺防治的保護因子，但亦可能提高自殺 的風險性", "自殺是單一因子決定的結果；自殺亦為一過程，由意念、行為意圖、採取自殺行為，期間 長短不一", "性別、年齡、職業、突發事件等原因，都可能成為自殺行為的危險因子", "大多數想要採取自殺行為的人，會發出求救信號；若能及時伸出援手，提供適當支持，可 避免遺憾發生"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00431', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '下列何者屬於職場霸凌（workplacebullying）？', '["某主管認為某員工近期工作表現不佳，因而將該員工請來辦公室談話", "某組內多位員工對於特定同事不滿，因而長期使用各種手法，阻止該同事順利工作", "某組內多位員工認為組長該次分工不均，因而找組長理論", "某員工因家中事故扣光帶薪假，因此遭到主管關切"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00432', 'public-health-specialist', 'public-health-specialist-moex-112-aaf759af', 'sub-public-health-specialist-02', NULL, 'essay', '近年來學界及媒體，以健保給付不足導致臺灣人平均餘命由過去比韓
